# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, request, redirect, session, url_for
from urllib.parse import urlencode
from jose import jwt
import requests
import json
import os

app = Flask(__name__)
app.secret_key = os.environ['SECRET_KEY']

client_id = os.environ['CLIENT_ID']
client_secret = os.environ['CLIENT_SECRET']
redirect_uri = os.environ['REDIRECT_URI']
authorization_url = os.environ['AUTHORIZATION_URL']
token_url = os.environ['TOKEN_URL']
userinfo_url = os.environ['USERINFO_URL']


@app.route('/')
def home():
    return redirect(authorization_url)


@app.route('/callback')
def callback():
    code = request.args.get('code')

    headers = {'Content-Type': 'application/x-www-form-urlencoded'}

    payload = {
        'grant_type': 'authorization_code',
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'client_secret': client_secret,
        'code': code,
    }

    token_response = requests.post(
        token_url,
        headers=headers,
        data=payload
    )

    tokens = json.loads(token_response.text)
    id_token = tokens['id_token']

    headers = {'Authorization': 'Bearer ' + id_token}

    userinfo_response = requests.get(userinfo_url, headers=headers)

    userinfo = userinfo_response.text
    decoded_userinfo = jwt.decode(userinfo, algorithms=['HS256'])

    session['userinfo'] = decoded_userinfo

    return "User authenticated and info stored in session."


if __name__ == '__main__':
    app.run(debug=True)